import * as React from 'react';
import { useTransferPanelContext } from '../hooks/PanelContext';
import { useTransferContext } from '../hooks/TransferContext';
import { TransferOptionContextProvider } from '../hooks/TransferOptionContext';
import type { TransferOption, TransferValue } from '../interface';

export const TransferOptionProvider = <V extends TransferValue = string>({
  option,
  children,
}: {
  option: TransferOption<V>;
  children: React.ReactElement;
}) => {
  const { toggle, valueSet, searchValue } = useTransferContext<V>();
  const { optionRenderer } = useTransferPanelContext<V>();
  const isChecked = valueSet.has(option.value);

  return (
    <TransferOptionContextProvider
      value={{
        toggle,
        isChecked,
        option,
        searchValue,
        disabled: option.disabled || false,
      }}
    >
      {optionRenderer ? optionRenderer({ option, isChecked, toggle }) : children}
    </TransferOptionContextProvider>
  );
};
